//별점1
const star=document.querySelectorAll('.star-grp .star');
let curring=0;
const rLabels=['','별로예요','아쉬워요','괜찮아요','좋아요!','최고예요! ⭐'];
function hoverrander(idx){star.forEach((st,i)=>{const n=+st.dataset.n;st.textContent=n<=idx?'★':'☆';st.classList.toggle('lit',n<=idx);document.querySelector('.rating-label').textContent=rLabels[idx];})};
star.forEach((ster,i)=>{
ster.addEventListener('mouseenter',function(){hoverrander(this.dataset.n);this.style.transform='scale(1.2)';});
ster.addEventListener('mouseleave',function(){hoverrander(curring);this.style.transform='scale(1)';});
ster.addEventListener('click',function(){curring=+this.dataset.n;hoverrander(this.dataset.n);document.querySelector('.rating-label').textContent='✓ '+rLabels[curring]+` [${curring}/5] 점`;const toastdiv=document.createElement('div');toastdiv.className='toast show success';const alertel=`<i class='star_icon'>⭐</i><div class='alert_box big'><h5 class='tit'>${curring}점</h5><p class='info'>${rLabels[curring]}</p></div>`;toastdiv.innerHTML=alertel;toastdiv.innerHTML+=`<button type='button' class='toast_close'>X</button>`;document.querySelector('.toast_containter').appendChild(toastdiv);
setTimeout(()=>{toastdiv.classList.remove('show');setTimeout(()=>{toastdiv.remove();},1000);},1800);
document.querySelector('.toast_close').addEventListener('click',function(){toastdiv.remove();});});
});
