let isclick3=false;
document.querySelector('#fi-inp').addEventListener('change',function(){let fi_list=document.querySelector('.fi-list');let fi_item_len=fi_list.childNodes.length;let file=this.files;if(!fi_list)return;[...file].forEach((el)=>{const li_item=document.createElement('div');li_item.className='fi-item';const itemhtml=`<i class='fi-icon'>📄</i><span class='fi-name'>${el.name}</span><span class='fi-size'>${(el.size/1024).toFixed(1)}KB</span><span class='fi-close'>✕</span>`;li_item.innerHTML=itemhtml;fi_list.appendChild(li_item);document.querySelector('.file-score .num').textContent=fi_item_len+1;});
